_DECL_TLINKED_LIST(FRenderResourcePtr);
typedef struct {
  /**
	 * Destructor used to catch unreleased resources.
	 */
	void (__thiscall *Dtor)(FRenderResource *);

	/**
	 * Initializes the dynamic RHI resource and/or RHI render target used by this resource.
	 * Called when the resource is initialized, or when reseting all RHI resources.
	 * Resources that need to initialize after a D3D device reset must implement this function.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *InitDynamicRHI)(FRenderResource *);

	/**
	 * Releases the dynamic RHI resource and/or RHI render target resources used by this resource.
	 * Called when the resource is released, or when reseting all RHI resources.
	 * Resources that need to release before a D3D device reset must implement this function.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *ReleaseDynamicRHI)(FRenderResource *);

	/**
	 * Initializes the RHI resources used by this resource.
	 * Called when the resource is initialized.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *InitRHI)(FRenderResource *);

	/**
	 * Releases the RHI resources used by this resource.
	 * Called when the resource is released.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *ReleaseRHI)(FRenderResource *);

	/**
	 * Initializes the resource.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *InitResource)(FRenderResource *);

	/**
	 * Prepares the resource for deletion.
	 * This is only called by the rendering thread.
	 */
	void (__thiscall *ReleaseResource)(FRenderResource *);

  /**
	 * @return The resource's friendly name.  Typically a UObject name.
	 */
	FString (__thiscall *GetFriendlyName)(const FRenderResource *);
} VfTable__FRenderResource;
/* A rendering resource which is owned by the rendering thread. */
