  BYTE pad_maybe_CachedPhysSMDataMap[60]; ///< 	Mapping between a particular static mesh used in the level and indices of pre-cooked physics data for it at various scales.
                                          ///< 	Index in FCachedPhysSMData refers to object in the CachedPhysSMDataStore.
  INT CachedPhysSMDataVersion;          ///< 	Indicates version that CachedPhysSMDataMap was created at.
                                        ///< 	Compared against CurrentCachedPhysDataVersion.
  TArray_FKCachedConvexData CachedPhysSMDataStore; ///< 	Store of processsed physics data for static meshes at different scales.
