  BYTE pad_maybe_CachedPhysPerTriSMDataMap[60]; ///< 	Store of physics cooked mesh data for per-triangle static mesh collision.
                                                ///< 	Index in FCachedPerTriPhysSMData refers to object in the CachedPhysPerTriSMDataStore.
  TArray_FKCachedPerTriData CachedPhysPerTriSMDataStore; ///< 	Store of processsed physics data for static meshes per-tri collision at different scales.
                                                         ///< 	Use CachedPhysPerTriSMDataMap to find index into this array.
  FKAggregateGeom ConvexBSPAggGeom;     ///< Simplified collision data for the mesh (convex hulls).
  FKCachedConvexData CachedPhysConvexBSPData; ///< Cached BSP convex hulls data for use with the physics engine.
