typedef struct FViewport  FViewport;
typedef struct {
  void (__thiscall *Precache)(FViewportClient *);
	void (__thiscall *RedrawRequested)(FViewportClient *, FViewport* Viewport);
	void (__thiscall *Draw)(FViewportClient *, FViewport* Viewport,FCanvas* Canvas);

	/**
	* Converts the character to a suitable FName and has the app check if a global hotkey was pressed.
	* Used for editor viewports.
	* @param	Viewport - The viewport which the keyboard input is from.
	* @param	KeyName - The key that was pressed
	*/
	void (__thiscall *CheckIfGlobalHotkey)(FViewportClient *, FViewport* Viewport, FName KeyName);

	/**
	 * Check a key event received by the viewport.
	 * If the viewport client uses the event, it should return true to consume it.
	 * @param	Viewport - The viewport which the key event is from.
	 * @param	ControllerId - The controller which the key event is from.
	 * @param	Key - The name of the key which an event occured for.
	 * @param	Event - The type of event which occured.
	 * @param	AmountDepressed - For analog keys, the depression percent.
	 * @param	bGamepad - input came from gamepad (ie xbox controller)
	 * @return	True to consume the key event, false to pass it on.
	 */
	UBOOL (__thiscall *InputKey)(FViewportClient *, FViewport* Viewport, INT ControllerId,
    FName Key, EInputEvent Event, float AmountDepressed,UBOOL bGamepad);

	/**
	 * Check an axis movement received by the viewport.
	 * If the viewport client uses the movement, it should return true to consume it.
	 * @param	Viewport - The viewport which the axis movement is from.
	 * @param	ControllerId - The controller which the axis movement is from.
	 * @param	Key - The name of the axis which moved.
	 * @param	Delta - The axis movement delta.
	 * @param	DeltaTime - The time since the last axis update.
	 * @return	True to consume the axis movement, false to pass it on.
	 */
	UBOOL (__thiscall *InputAxis)(FViewportClient *, FViewport* Viewport,
    INT ControllerId, FName Key, float Delta, float DeltaTime,UBOOL bGamepad);

	/**
	 * Check a character input received by the viewport.
	 * If the viewport client uses the character, it should return true to consume it.
	 * @param	Viewport - The viewport which the axis movement is from.
	 * @param	ControllerId - The controller which the axis movement is from.
	 * @param	Character - The character.
	 * @return	True to consume the character, false to pass it on.
	 */
	UBOOL (__thiscall *InputChar)(FViewportClient *, FViewport* Viewport,INT ControllerId,TCHAR Character);

	/** @name Obsolete input interface.  Called by the new interface to ensure implementors of the old interface aren't broken. */
	//@{
	void (__thiscall *InputKey_OLD)(FViewportClient *, FViewport* Viewport,
    FName Key, EInputEvent Event, float AmountDepressed, UBOOL bGamepad);
	void (__thiscall *InputAxis_OLD)(FViewportClient *, FViewport* Viewport,
    FName Key, float Delta, float DeltaTime, UBOOL bGamepad);
	void (__thiscall *InputChar_OLD)(FViewportClient *, FViewport* Viewport, TCHAR Character);
	//@}

	UBOOL (__thiscall *WantsPollingMouseMovement)(const FViewportClient *);

	/**
	 * Sets whether or not a controller is actively plugged in
	 * @param InControllID - Unique ID of the joystick
	 * @param bInConnected - TRUE, if the joystick is valid for input
	 */
	void (__thiscall *OnJoystickPlugged)(FViewportClient *,
    const UINT InControllerID, const UINT InType, const UINT bInConnected);


	/** Returns the platform specific forcefeedback manager this viewport associates with the specified controller. */
	struct UForceFeedbackManager *(__thiscall *GetForceFeedbackManager)(FViewportClient *, INT ControllerId);

	/**
	 * @return whether or not this Controller has Tilt Turned on
	 **/
	UBOOL (__thiscall *IsControllerTiltActive)(const FViewportClient *, INT ControllerID );

	/**
	 * sets whether or not the Tilt functionality is turned on
	 **/
	void (__thiscall *SetControllerTiltDesiredIfAvailable)(FViewportClient *, INT ControllerID, UBOOL bActive );

	/**
	 * sets whether or not the Tilt functionality is turned on
	 **/
	void (__thiscall *SetControllerTiltActive)(FViewportClient *, INT ControllerID, UBOOL bActive );

	/**
	 * sets whether or not to ONLY use the tilt input controls
	 **/
	void (__thiscall *SetOnlyUseControllerTiltInput)(FViewportClient *, INT ControllerID, UBOOL bActive );


	void (__thiscall *MouseMove)(FViewportClient *, FViewport* Viewport, INT X, INT Y);

	/**
	 * Called when the mouse is moved while a window input capture is in effect
	 *
	 * @param	InViewport	Viewport that captured the mouse input
	 * @param	InMouseX	New mouse cursor X coordinate
	 * @param	InMouseY	New mouse cursor Y coordinate
	 */
	void (__thiscall *CapturedMouseMove)(FViewportClient *, FViewport* InViewport, INT InMouseX, INT InMouseY );


	/**
	 * Retrieves the cursor that should be displayed by the OS
	 *
	 * @param	Viewport	the viewport that contains the cursor
	 * @param	X			the x position of the cursor
	 * @param	Y			the Y position of the cursor
	 * 
	 * @return	the cursor that the OS should display
	 */
	EMouseCursor (__thiscall *GetCursor)(FViewportClient *, FViewport* Viewport,INT X,INT Y);

	void (__thiscall *LostFocus)(FViewportClient *, FViewport* Viewport);
	void (__thiscall *ReceivedFocus)(FViewportClient *, FViewport* Viewport);
	UBOOL (__thiscall *IsFocused)(FViewportClient *, FViewport* Viewport);

	void (__thiscall *CloseRequested)(FViewportClient *, FViewport* Viewport);

	UBOOL (__thiscall *RequiresHitProxyStorage)(FViewportClient *);

	/**
	 * Determines whether this viewport client should receive calls to InputAxis() if the game's window is not currently capturing the mouse.
	 * Used by the UI system to easily receive calls to InputAxis while the viewport's mouse capture is disabled.
	 */
	UBOOL (__thiscall *RequiresUncapturedAxisInput)(const FViewportClient *);

	/**
	* Determine if the viewport client is going to need any keyboard input
	* @return TRUE if keyboard input is needed
	*/
	UBOOL (__thiscall *RequiresKeyboardInput)(const FViewportClient *);

  UObject *(__thiscall *GetUObject)(FViewportClient *);
} VfTable__FViewportClient;
/**
 * An abstract interface to a viewport's client.
 * The viewport's client processes input received by the viewport, and draws the viewport.
 */
struct FViewportClient {
  VfTable__FViewportClient *vftable;
};

